async function main() {
  console.log('insert 시작: ' + DATA.length + '개');
  let successCount = 0;
  let skipCount = 0;
  let errorCount = 0;

  for (let i = 0; i < DATA.length; i++) {
    const item = DATA[i];
    const { error } = await supabase.from('businesses').insert(item);
    if (error) {
      if (error.code === '23505') {
        console.log((i + 1) + '번 스킵 (중복): ' + item.name);
        skipCount++;
      } else {
        console.log((i + 1) + '번 에러: ' + item.name + ' / ' + error.message);
        errorCount++;
      }
    } else {
      console.log((i + 1) + '번 완료: ' + item.name);
      successCount++;
    }
    await new Promise(r => setTimeout(r, 100));
  }

  console.log('');
  console.log('=== 완료 ===');
  console.log('성공: ' + successCount + '개');
  console.log('스킵: ' + skipCount + '개');
  console.log('에러: ' + errorCount + '개');
}

main().catch(console.error);